export function getQuestionByLetter(letter: string): QuestionData | undefined {
  const normalizedLetter = letter === 'ه' ? 'هـ' : letter;
  return QUESTIONS_DATA.find((q) => q.letter === letter || q.letter === normalizedLetter);
}

